"/* ==========================================================================
   AURA DESIGN SYSTEM & STYLESHEET
   ========================================================================== */

/* 1. Global Variables & Tokens */
:root {
    /* Colors */
    --color-bg-base: #07080d;
    --color-bg-surface: rgba(18, 20, 36, 0.45);
    --color-bg-surface-hover: rgba(26, 29, 51, 0.65);
    --color-bg-card-header: rgba(255, 255, 255, 0.02);

    --color-text-primary: #f8fafc;
    --color-text-secondary: #94a3b8;
    --color-text-muted: #64748b;

    --color-indigo: #6366f1;
    --color-indigo-glow: rgba(99, 102, 241, 0.25);
    --color-emerald: #10b981;
    --color-emerald-glow: rgba(16, 185, 129, 0.2);
    --color-rose: #f43f5e;
    --color-rose-glow: rgba(244, 63, 94, 0.25);
    --color-amber: #f59e0b;
    --color-amber-glow: rgba(245, 158, 11, 0.2);

    --border-light: rgba(255, 255, 255, 0.07);
    --border-focus: rgba(99, 102, 241, 0.5);

    /* Layout & Styling */
    --radius-sm: 8px;
    --radius-md: 16px;
    --radius-lg: 24px;
    --radius-full: 9999px;

    --font-primary: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    --font-display: 'Outfit', sans-serif;

    --transition-fast: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-normal: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 0.6s cubic-bezier(0.4, 0, 0.2, 1);

    --shadow-premium: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
    --glass-blur: blur(20px);
}

/* 2. Reset & Base Setup */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html, body {
    width: 100%;
    height: 100%;
    overflow: hidden;
    background-color: var(--color-bg-base);
    color: var(--color-text-primary);
    font-family: var(--font-primary);
    font-size: 16px;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
}

